INSERT INTO `chatbot_feedback_logs` VALUES (1,'kamu ini siapa','Saya adalah Analis yang bertugas di Bagian Kerjasama Setda Kota Samarinda.','rendah','[\"FAQ-siapa-admin-si-kerja-samarinda\", \"FAQ-siapa-saja-yang-dapat-melakukan-kerja-sama-daerah\", \"FAQ-siapa-yang-menjadi-petugas-permohonan-kerja-sama-daerah\"]','needs_review','low_confidence','landing_widget','2026-03-26 06:59:31','2026-03-26 06:59:31'),(2,'Bagaimana alur proses kerjasama daerah dari awal sampai akhir?','Berikut adalah alur proses kerja sama daerah dari awal sampai akhir berdasarkan konteks terverifikasi:\n\n1. Pengajuan usulan dari menu Kelola Permohonan -> Tambah.\n2. Dokumen utama: Surat Permohonan, KAK, Draft Naskah (MoU/PKS), Profil Mitra.\n3. Validasi administrasi oleh Bagian Kerja Sama/TKKSD. Jika tidak lengkap: Perlu Revisi.\n4. Pembahasan teknis/legal bersama tim terkait.\n5. Persetujuan akhir dan penandatanganan.\n6. Monitoring & Evaluasi (Monev) berkala.\n\nTindak lanjut: Setelah proses tersebut selesai, pengguna dapat melihat status permohonan kerja sama daerahnya di menu Kelola Permohonan.','rendah','[\"SOP-001\", \"FAQ-apa-itu-si-kerja-samarinda\", \"FAQ-apa-fasilitas-utama-dari-si-kerja-samarinda\", \"FAQ-apa-yang-perlu-disiapkan-sebelum-mengajukan-permohonan-kerja-sama-daerah\", \"FAQ-apa-dasar-hukum-penyelenggaraan-kerja-sama-daerah\", \"FAQ-apa-yang-dimaksud-tim-koordinasi-kerja-sama-daerah-tkksd\"]','needs_review','low_confidence','landing_widget','2026-05-18 08:45:20','2026-05-18 08:45:20'),(3,'Bagaimana alur proses kerjasama daerah dari awal sampai akhir?','Berikut adalah alur proses kerjasama daerah dari awal sampai akhir berdasarkan konteks terverifikasi:\n\n1. Pengajuan usulan dari menu Kelola Permohonan -> Tambah.\n2. Dokumen utama: Surat Permohonan, KAK, Draft Naskah (MoU/PKS), Profil Mitra.\n3. Validasi administrasi oleh Bagian Kerja Sama/TKKSD. Jika tidak lengkap: Perlu Revisi.\n4. Pembahasan teknis/legal bersama tim terkait.\n5. Persetujuan akhir dan penandatanganan.\n6. Monitoring & Evaluasi (Monev) berkala.\n\nTindak lanjut: Setelah proses tersebut selesai, Anda dapat melihat hasilnya di menu Kelola Permohonan.','rendah','[\"SOP-001\", \"FAQ-apa-itu-si-kerja-samarinda\", \"FAQ-apa-fasilitas-utama-dari-si-kerja-samarinda\", \"FAQ-apa-yang-perlu-disiapkan-sebelum-mengajukan-permohonan-kerja-sama-daerah\", \"FAQ-apa-dasar-hukum-penyelenggaraan-kerja-sama-daerah\", \"FAQ-apa-yang-dimaksud-tim-koordinasi-kerja-sama-daerah-tkksd\"]','needs_review','low_confidence','landing_widget','2026-05-18 08:45:25','2026-05-18 08:45:25'),(4,'resep es campur','Tidak ada konteks yang relevan untuk pertanyaan \"resep es campur\" di dalam sistem SiKerja. \n\nTindak lanjut: Anda dapat mencari resep es campur di internet atau buku masak.','rendah','[]','needs_review','low_confidence','landing_widget','2026-05-18 08:46:19','2026-05-18 08:46:19'),(5,'resep es campur','Maaf, saya tidak bisa membantu dengan pertanyaan tersebut karena konteks tidak tersedia. Saya dapat membantu Anda dengan pertanyaan lain atau memberikan informasi umum tentang resep es campur jika Anda ingin mencoba.','rendah','[]','needs_review','low_confidence','landing_widget','2026-05-21 06:11:06','2026-05-21 06:11:06'),(6,'pks itu apa','Berdasarkan Konteks Terverifikasi [CTX-2], Perjanjian Kerja Sama (PKS) adalah dokumen kerja sama antara Daerah dengan Daerah Lain dan/atau Daerah dengan Pihak Ketiga, yang memuat hak dan kewajiban.\n\nTindak lanjut: Anda dapat mencari informasi lebih lanjut tentang PKS di Bagian Kerja Sama Setda Kota Samarinda.','rendah','[\"SOP-001\", \"FAQ-apa-yang-dimaksud-perjanjian-kerja-sama-pks\", \"FAQ-apa-saja-tahapan-penyelenggaraan-kerja-sama-daerah\"]','needs_review','low_confidence','landing_widget','2026-05-21 06:11:18','2026-05-21 06:11:18'),(7,'Regulasi Kerjasama Daearh','Berikut adalah informasi terkait Regulasi Kerjasama Daerah:\n\n- Regulasi Kerjasama Daerah (RKD) adalah undang-undang yang mengatur kerjasama antara pemerintah daerah dengan pemerintah pusat dan antara pemerintah daerah dengan pemerintah daerah lainnya.\n- RKD bertujuan untuk meningkatkan efisiensi dan efektifitas pengelolaan sumber daya dan kegiatan pemerintah daerah.\n- RKD juga mengatur tentang peran dan tanggung jawab dari pemerintah daerah dalam mengelola sumber daya dan kegiatan pemerintah daerah.\n\nTindak lanjut praktis bagi pengguna: Silakan mengunjungi /alur/RKD untuk mendapatkan informasi lebih lanjut tentang Regulasi Kerjasama Daerah.','rendah','[\"FAQ-siapa-admin-si-kerja-samarinda\"]','needs_review','low_confidence','landing_widget','2026-05-21 06:16:07','2026-05-21 06:16:07'),(8,'Bagaimana alur proses kerjasama daerah dari awal sampai akhir?','Berikut adalah alur proses kerjasama daerah dari awal sampai akhir:\n1. Login melalui SSO Samarinda.\n2. Pengajuan usulan dari menu Kelola Permohonan -> Tambah.\n3. Dokumen utama: Surat Permohonan, KAK, Draft Naskah (MoU/PKS), Profil Mitra.\n4. Validasi administrasi oleh Bagian Kerja Sama/TKKSD. Jika tidak lengkap: Perlu Revisi.\n5. Pembahasan teknis/legal bersama tim terkait.\n6. Persetujuan akhir dan penandatanganan.\n7. Monitoring & Evaluasi (Monev) berkala.\n\nSilakan mengunjungi halaman /alur untuk informasi lebih lanjut tentang alur proses kerjasama daerah.','rendah','[\"SOP-001\", \"FAQ-apa-itu-si-kerja-samarinda\", \"FAQ-apa-fasilitas-utama-dari-si-kerja-samarinda\", \"FAQ-apa-yang-perlu-disiapkan-sebelum-mengajukan-permohonan-kerja-sama-daerah\", \"FAQ-apa-dasar-hukum-penyelenggaraan-kerja-sama-daerah\", \"FAQ-apa-yang-dimaksud-tim-koordinasi-kerja-sama-daerah-tkksd\"]','needs_review','low_confidence','landing_widget','2026-06-05 05:23:44','2026-06-05 05:23:44'),(9,'peraturan apa saja yang terkait','Berikut adalah beberapa peraturan yang terkait dengan kerjasama daerah:\n1. Undang-Undang Republik Indonesia Nomor 23 Tahun 2014 tentang Pemerintahan Daerah\n2. Peraturan Pemerintah Republik Indonesia Nomor 28 Tahun 2018 tentang Kerja Sama Daerah\n3. Peraturan Menteri Dalam Negeri Republik Indonesia Nomor 22 Tahun 2020 tentang Tata Cara Kerja Sama Daerah dengan Daerah Lain dan Kerja Sama Daerah dengan Pihak Ketiga\n4. Peraturan Menteri Dalam Negeri Republik Indonesia Nomor 25 Tahun 2020 tentang Tata Cara Kerja Sama Daerah dengan Pemerintah Daerah di Luar Negeri dan Kerja Sama Daerah dengan Lembaga di Luar Negeri\n5. Peraturan Daerah Kota Samarinda Nomor 7 Tahun 2020 tentang Kerja Sama Daerah\n\nSilakan mengunjungi halaman /faq untuk informasi lebih lanjut tentang peraturan yang terkait dengan kerjasama daerah.','rendah','[\"SOP-001\", \"FAQ-apa-itu-si-kerja-samarinda\", \"FAQ-apa-yang-perlu-disiapkan-sebelum-mengajukan-permohonan-kerja-sama-daerah\", \"FAQ-apa-dasar-hukum-penyelenggaraan-kerja-sama-daerah\", \"FAQ-apa-yang-dimaksud-sinergi\", \"FAQ-apa-saja-objek-yang-dapat-dikerjasamakan\"]','needs_review','low_confidence','landing_widget','2026-06-05 05:24:06','2026-06-05 05:24:06'),(10,'resep es campur','Maaf, saya tidak dapat membantu dengan resep es campur karena itu tidak terkait dengan aplikasi SiKerja. \nSilakan kembali ke topik SiKerja untuk informasi tentang kerjasama daerah atau mengunjungi Bagian Kerja Sama Setda Kota Samarinda untuk pertanyaan lebih lanjut.','rendah','[]','needs_review','low_confidence','landing_widget','2026-06-05 05:28:55','2026-06-05 05:28:55');
