INSERT INTO `faq` VALUES (3,'88bc0834-67dc-11ed-a951-1d53f8a415f6','Bagaimana Cara Membuat Permohonan ?','<p>Untuk seluruh tata cara membuat permohonan dapat dilihat pada halaman Indormasi, dengan judul dokumen Buku Petunjuk Teknis Penggunaan Si Kerja Samarinda</p>','bagaimana-cara-membuat-permohonan','2022-11-18 23:34:00','2022-12-14 21:35:35'),(4,'c3fa01b8-71e5-11ed-abb5-1f27f1e0136c','Apa itu Si Kerja Samarinda ?','Si Kerja Samarinda merupakan akronim dari Sistem Kerja Sama Samarinda yang merupakan sebuah sistem informasi manajemen yang berisi seluruh business process kerja sama daerah berdasarkan Peraturan Pemerintah Republik Indonesia Nomor 28 Tahun 2018 dan Peraturan Menteri Dalam Negeri Republik Indonesia Nomor 22 Tahun 2020 yang memanfaatkan teknologi informasi.','apa-itu-si-kerja-samarinda','2022-12-01 18:05:16','2022-12-01 18:05:16'),(5,'5879e898-71e7-11ed-ab65-31c29b27b155','Apa fasilitas utama dari Si Kerja Samarinda ?','<p>a. Pengajuan Kerja Sama Daerah</p>\r\n<p>b. Pengetahuan Kerja Sama Daerah</p>\r\n<p>c. Statistik dan Data Kerja Sama Daerah</p>\r\n<p>d. FAQ Kerja Sama Daerah</p>','apa-fasilitas-utama-dari-si-kerja-samarinda','2022-12-01 18:16:35','2022-12-14 19:06:16'),(6,'edc5b73e-724a-11ed-8b86-f5eb1711d54d','Apa yang perlu disiapkan sebelum mengajukan permohonan kerja sama daerah?','<p>a. data pribadi 2 (dua) orang narahubung, seperti NIK, NIP/No. Kepegawaian/Nomor Karyawan, No. HP(WA), email, foto dan surat tugas.</p>\r\n<p>b. narasi terkait keperluan Persiapan Kerja Sama Daerah yang berisi :</p>\r\n<ul>\r\n<li>Latar Belakang</li>\r\n<li>Maksud dan Tujuan</li>\r\n<li>Lokasi Kerja Sama Daerah</li>\r\n<li>Ruang Lingkup</li>\r\n<li>Jangka Waktu</li>\r\n<li>Manfaat</li>\r\n<li>Analisis Dampak Sosial dan Lingkungan sesuai Bidang yang Dikerjasamakan</li>\r\n<li>Pembiayaan Contoh dapat dilihat pada Halaman Informasi</li>\r\n</ul>','apa-yang-perlu-disiapkan-sebelum-mengajukan-permohonan-kerja-sama-daerah','2022-12-02 06:09:26','2022-12-14 19:13:47'),(7,'ffbaa0ca-724b-11ed-afc9-6db129e93a84','Apa dasar hukum penyelenggaraan kerja sama daerah?','<ol>\r\n<li>Undang-Undang Republik Indonesia Nomor 23 Tahun 2014 tentang Pemerintahan Daerah</li>\r\n<li>Peraturan Pemerintah Republik Indonesia Nomor 28 Tahun 2018 tentang Kerja Sama Daerah</li>\r\n<li>Peraturan Menteri Luar Negeri Republik Indonesia Nomor 03 Tahun 2019 tentang Panduan Umum Hubungan Luar Negeri oleh Pemerintah Daerah</li>\r\n<li>Peraturan Menteri Dalam Negeri Republik Indonesia Nomor 22 Tahun 2020 tentang Tata Cara Kerja Sama Daerah dengan Daerah Lain dan Kerja Sama Daerah dengan Pihak Ketiga</li>\r\n<li>Peraturan Menteri Dalam Negeri Republik Indonesia Nomor 25 Tahun 2020 tentang Tata Cara Kerja Sama Daerah dengan Pemerintah Daerah di Luar Negeri dan Kerja Sama Daerah dengan Lembaga di Luar Negeri</li>\r\n<li>Peraturan Daerah Kota Samarinda Nomor 7 Tahun 2020 tentang Kerja Sama Daerah</li>\r\n</ol>','apa-dasar-hukum-penyelenggaraan-kerja-sama-daerah','2022-12-02 06:17:05','2022-12-14 21:00:09'),(9,'f79b5038-79fd-11ed-9d93-e9be2fd52fec','Apa yang dimaksud Tim Koordinasi Kerja Sama Daerah (TKKSD) ?','TKKSD adalah tim yang dibentuk oleh Kepala Daerah untuk membantu Kepala Daerah dalam menyiapkan kerja sama daerah.','apa-yang-dimaksud-tim-koordinasi-kerja-sama-daerah-tkksd','2022-12-12 01:18:40','2022-12-12 01:18:40'),(10,'1922f328-79fe-11ed-bb84-73df5e7dd971','Apa yang dimaksud Kerja Sama Daerah dengan Daerah Lain (KSDD)?','KSDD adalah  usaha  bersama  yang  dilakukan oleh Daerah dengan Daerah lain dalam rangka penyelenggaraan urusan pemerintahan yang menjadi kewenangan Daerah untuk  kesejahteraan  masyarakat dam percepatan pemenuhan pelayanan publik.','apa-yang-dimaksud-kerja-sama-daerah-dengan-daerah-lain-ksdd','2022-12-12 01:19:36','2022-12-12 01:19:36'),(11,'381c60d4-79fe-11ed-a4a0-37ec98c0fb48','Apa yang dimaksud Kerja Sama Daerah dengan Pihak Ketiga (KSDPK)?','KSDPK adalah usaha bersama yang dilakukan    oleh    Daerah    dengan    Pihak Ketiga dalam rangka penyelenggaraan urusan pemerintahan yang menjadi kewenangan Daerah, untuk meningkatkan kesejahteraan masyarakat dan percepatan pemenuhan pelayanan publik.','apa-yang-dimaksud-kerja-sama-daerah-dengan-pihak-ketiga-ksdpk','2022-12-12 01:20:28','2022-12-12 01:20:28'),(12,'459cefe4-79fe-11ed-b1b7-3d99a758823c','Apa yang dimaksud Kerja Sama Wajib?','Kerja Sama Wajib adalah Kerja Sama Daerah dengan Daerah Lain yang dilaksanakan oleh 2 (dua) atau lebih Daerah yang berbatasan, untuk penyelenggaraan urusan pemerintahan yang memiliki eksternalitas lintas Daerah dan penyediaan layanan public yang lebih efisien jika dikelola bersama.','apa-yang-dimaksud-kerja-sama-wajib','2022-12-12 01:20:51','2022-12-12 01:20:51'),(13,'58a93c8c-79fe-11ed-9bea-d96871135258','Apa yang dimaksud Kesepakatan Bersama?','Kesepakatan Bersama adalah dokumen kerja sama antara Daerah dengan Daerah Lain dan/atau Daerah dengan Pihak Ketiga, yang berisi kesepakatan yang isinya bersifat umum.','apa-yang-dimaksud-kesepakatan-bersama','2022-12-12 01:21:23','2022-12-12 01:21:23'),(14,'67cf3d74-79fe-11ed-8a15-118bf2de8b36','Apa yang dimaksud Perjanjian Kerja Sama (PKS)?','Perjanjian Kerja Sama adalah dokumen kerja sama antara Daerah dengan Daerah Lain dan/atau Daerah dengan Pihak Ketiga, yang memuat hak dan kewajiban.','apa-yang-dimaksud-perjanjian-kerja-sama-pks','2022-12-12 01:21:48','2022-12-12 01:21:48'),(15,'cc0f9aae-79fe-11ed-9a9e-c54d114d4d59','Apa yang dimaksud Sinergi?','Sinergi adalah pembagian peran dan tanggungjawab antara Pemerintah Pusat dan Pemerintah Daerah untuk memastikan bahwa perencanaan dan pelaksanaan pembangunan sesuai dengan ketentuan peraturan perundang-undangan.','apa-yang-dimaksud-sinergi','2022-12-12 01:24:37','2022-12-12 01:24:37'),(16,'d9989ab8-79fe-11ed-86c7-c5e417390ef0','Apa yang dimaksud Nota Kesepakatan?','Nota Kesepakatan adalah Dokumen Kesepakatan Sinergi yang berisi substansi pokok berupa tugas dan tanggungjawab Pemerintah Pusat dan Pemerintah Daerah yang bersifat mengikat.','apa-yang-dimaksud-nota-kesepakatan','2022-12-12 01:24:59','2022-12-12 01:24:59'),(17,'5ad608c2-79ff-11ed-a4c8-e7fb39f40f71','Apa saja objek yang dapat dikerjasamakan?','<ol>\r\n<li>Bidang Pendidikan</li>\r\n<li>Bidang Kesehatan</li>\r\n<li>Bidang Pekerjaan Umum dan Penataan Ruang</li>\r\n<li>Bidang Perumahan Rakyat dan Kawasan Permukiman</li>\r\n<li>Bidang Ketentraman, Ketertiban Umum, dan Perlindungan Masyarakat</li>\r\n<li>Bidang Sosial&nbsp;</li>\r\n<li>Bidang Tenaga Kerja</li>\r\n<li>Bidang Pemberdayaan Perempuan dan Perlindungan Anak</li>\r\n<li>Bidang Pangan</li>\r\n<li>Bidang Pertanahan</li>\r\n<li>Bidang Lingkungan Hidup</li>\r\n<li>Bidang Administrasi Kependudukan dan Pencatatan Sipil</li>\r\n<li>Bidang Pemberdayaan Masyarakat dan Desa</li>\r\n<li>Bidang Pengendalian Penduduk dan Keluarga Berencana</li>\r\n<li>Bidang Perhubungan</li>\r\n<li>Bidang Komunikasi dan Informatika</li>\r\n<li>Bidang Koperasi, Usaha Kecil, dan Menengah</li>\r\n<li>Bidang Penanaman Modal</li>\r\n<li>Bidang Kepemudaan dan Olah Raga</li>\r\n<li>Bidang Statistik</li>\r\n<li>Bidang Persandian</li>\r\n<li>Bidang Kebudayaan</li>\r\n<li>Bidang Perpustakaan</li>\r\n<li>Bidang Kearsipan</li>\r\n<li>Bidang Kelautan dan Perikanan</li>\r\n<li>Bidang Pariwisata</li>\r\n<li>Bidang Pertanian</li>\r\n<li>Bidang Kehutanan</li>\r\n<li>Bidang Energi dan Sumber daya Mineral</li>\r\n<li>Bidang Perdagangan</li>\r\n<li>Bidang Perindustrian</li>\r\n<li>Bidang Transmigrasi</li>\r\n</ol>','apa-saja-objek-yang-dapat-dikerjasamakan','2022-12-12 01:28:36','2022-12-14 21:03:12'),(18,'3cd11234-7c36-11ed-8575-29edf8588e9c','Apa saja tahapan penyelenggaraan Kerja Sama Daerah?','<ol>\r\n<li>Persiapan</li>\r\n<li>Penawaran</li>\r\n<li>Penyusunan Kesepakatan Bersama</li>\r\n<li>Penandatanganan Kesepakatan Bersama</li>\r\n<li>Persetujuan DPRD (Jika Diperlukan)</li>\r\n<li>Penyusunan PKS</li>\r\n<li>Penandatanganan PKS</li>\r\n<li>Pelaksanaan</li>\r\n<li>Penatausahaan</li>\r\n<li>Pelaporan</li>\r\n</ol>','apa-saja-tahapan-penyelenggaraan-kerja-sama-daerah','2022-12-14 21:06:30','2022-12-14 21:06:30'),(19,'5cdb8bc2-7c36-11ed-8019-d9aefe433a8e','Kondisi apa yang membuat Persetujuan DPRD diperlukan?','<p>Apabila rencana Kerja Sama Daerah membebani masyarakat dan daerah dan/atau pendanaan kerja sama belum dianggarkan dalam APBD tahun anggaran berjalan.</p>','kondisi-apa-yang-membuat-persetujuan-dprd-diperlukan','2022-12-14 21:07:24','2022-12-14 21:07:24'),(20,'6fd5a17c-7c36-11ed-b7a8-e3228478b015','Siapa Admin Si Kerja Samarinda?','<p>Analis yang bertugas di Bagian Kerjasama Setda Kota Samarinda</p>','siapa-admin-si-kerja-samarinda','2022-12-14 21:07:56','2022-12-14 21:07:56'),(21,'ce2c40d2-7c36-11ed-9378-ab809c27c871','Siapa saja yang dapat melakukan kerja sama daerah?','<ol>\r\n<li>Pemerintah Pusat</li>\r\n<li>Pemerintah Provinsi/Pemerintah Kabupaten/Pemerintah Kota Dalam Negeri dan Luar Negeri.</li>\r\n<li>Lembaga Dalam Negeri dan Luar Negeri</li>\r\n<li>Pihak Ketiga yang terdiri dari : Perseorangan, Badan Usaha yang Berbadan Hukum, Organisasi Kemasyarakatan baik yang berbadan hukum maupun tidak berbadan hukum.</li>\r\n</ol>','siapa-saja-yang-dapat-melakukan-kerja-sama-daerah','2022-12-14 21:10:34','2022-12-14 21:10:34'),(22,'03ab90c8-7c37-11ed-8ef4-ff6475dcb1b0','Siapa yang menjadi petugas permohonan kerja sama daerah?','<p>ASN/Non ASN/Karyawan/Karyawati pada organisasi atau perusahaan yang mendapat surat tugas dari pimpinannya sebagai narahubung yang bertanggungjawab untuk melakukan permohonan kerja sama daerah, penyusunan dokumen kerja sama daerah, dan pelaporan pelaksanaan kerja sama daerah yang telah ditandatangani.</p>','siapa-yang-menjadi-petugas-permohonan-kerja-sama-daerah','2022-12-14 21:12:04','2022-12-14 21:12:04'),(24,'c58cc2c2-0e2a-4e9b-9b4b-f8b57bd8cc0c','Apa Regulasi Kerjasama Daearh ?','<p>PERMENDAGRI&nbsp;Nomor&nbsp;22&nbsp;Tahun&nbsp;2020</p><p></p>',NULL,'2026-05-21 06:15:04','2026-05-21 06:15:50');
