DROP TABLE IF EXISTS `penjadwalan`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `penjadwalan` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `uuid` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `id_permohonan` int unsigned NOT NULL,
  `id_histori` int DEFAULT NULL,
  `tipe` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'desk_to_desk' COMMENT 'desk_to_desk | seremonial | hybrid',
  `tanggal` date NOT NULL,
  `waktu` time NOT NULL,
  `lokasi` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `agenda` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `keterangan` text COLLATE utf8mb4_unicode_ci,
  `created_by` bigint unsigned DEFAULT NULL,
  `status` int NOT NULL DEFAULT '1',
  `approved_by` bigint unsigned DEFAULT NULL,
  `approved_at` timestamp NULL DEFAULT NULL,
  `admin_comment` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `penjadwalan_uuid_unique` (`uuid`),
  KEY `penjadwalan_id_permohonan_foreign` (`id_permohonan`),
  KEY `penjadwalan_id_histori_index` (`id_histori`),
  KEY `penjadwalan_approved_by_foreign` (`approved_by`),
  KEY `penjadwalan_created_by_foreign` (`created_by`),
  CONSTRAINT `penjadwalan_approved_by_foreign` FOREIGN KEY (`approved_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `penjadwalan_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `penjadwalan_id_permohonan_foreign` FOREIGN KEY (`id_permohonan`) REFERENCES `permohonan` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
