DROP TABLE IF EXISTS `permohonan`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `permohonan` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `uuid` varchar(255) NOT NULL,
  `id_pemohon_0` int DEFAULT NULL,
  `id_pemohon_1` int DEFAULT NULL,
  `id_provinsi` int DEFAULT NULL,
  `id_kota` int DEFAULT NULL,
  `id_kategori` int DEFAULT NULL,
  `kode` varchar(255) DEFAULT NULL,
  `nama_instansi` varchar(255) DEFAULT NULL,
  `nomor_permohonan` varchar(255) DEFAULT NULL,
  `alamat` varchar(255) DEFAULT NULL,
  `lokasi` varchar(255) DEFAULT NULL,
  `kode_pos` varchar(255) DEFAULT NULL,
  `slug` varchar(255) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `telepon` varchar(255) DEFAULT NULL,
  `website` varchar(255) DEFAULT NULL,
  `status` varchar(255) DEFAULT NULL,
  `file_final` varchar(255) DEFAULT NULL,
  `label` longtext,
  `latar_belakang` longtext,
  `alasan_tolak` longtext,
  `maksud_tujuan` longtext,
  `lokasi_kerjasama` longtext,
  `pembiayaan` longtext,
  `analisis_dampak` longtext,
  `manfaat` longtext,
  `jangka_waktu` longtext,
  `tanggal_mulai` date DEFAULT NULL,
  `tanggal_berakhir` date DEFAULT NULL,
  `ruang_lingkup` longtext,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=97 DEFAULT CHARSET=latin1;
/*!40101 SET character_set_client = @saved_cs_client */;

