gaan informasi geospasial','2025-08-20 02:18:12','2025-08-20 02:18:12'),(87,'fa998ec2-cc87-4070-9e88-b730a5155e0f',138,27,64,6472,4,'PKS-B6GX99GB','Dinas Komunikasi dan Informatika','REQ/2026/0001','Jalan Subulus Salam Gg. Gunung Sari 2 RT.35 No.27',NULL,'75117','testing-kerjasama-baru','arifdwi286@gmail.com','082255949881',NULL,'3',NULL,'TESTING KERJASAMA BARU','TESTING KERJASAMA BARU',NULL,'TESTING KERJASAMA BARU','TESTING KERJASAMA BARU','TESTING KERJASAMA BARU','TESTING KERJASAMA BARU','TESTING KERJASAMA BARU','TESTING KERJASAMA BARU','2025-01-24','2026-01-25','TESTING KERJASAMA BARU','2026-01-21 23:05:02','2026-05-22 05:59:45'),(89,'7e6cbbee-d50f-43c1-8b66-097dd2962f6b',139,69,64,6402,3,'PKS-FMLKXXMT','Dinas Komunikasi','REQ/2026/0003','Jalan Subulus Salam Gg. Gunung Sari 2 RT.35 No.27',NULL,'75117','testing-kerjasama-data-instansi-perusahaan-lembaga','arifdwi286@gmail.com','082255949881',NULL,'1',NULL,'Testing Kerjasama Data Instansi / Perusahaan / Lembaga','Data Instansi / Perusahaan / Lembaga',NULL,'Data Instansi / Perusahaan / Lembaga','Data Instansi / Perusahaan / Lembaga','Data Instansi / Perusahaan / Lembaga','Data Instansi / Perusahaan / Lembaga','Data Instansi / Perusahaan / Lembaga','Data Instansi / Perusahaan / Lembaga','2025-01-24','2027-01-24','Data Instansi / Perusahaan / Lembaga','2026-01-25 18:12:13','2026-01-25 18:28:41'),(90,'0938d737-01ac-433a-a8a4-636d6d6ab756',139,48,12,1219,7,'PKS-SLGRZCLY','Dinas Komunikasi','REQ/2026/0004','Jalan Subulus Salam Gg. Gunung Sari 2 RT.35 No.27',NULL,'75117','jalan-subulus-salam-gg-gunung-sari-2-rt35-no27','arifdwi286@gmail.com','082255949881',NULL,'1',NULL,'Jalan Subulus Salam Gg. Gunung Sari 2 RT.35 No.27','Jalan Subulus Salam Gg. Gunung Sari 2 RT.35 No.27',NULL,'Jalan Subulus Salam Gg. Gunung Sari 2 RT.35 No.27','Jalan Subulus Salam Gg. Gunung Sari 2 RT.35 No.27','Jalan Subulus Salam Gg. Gunung Sari 2 RT.35 No.27','Jalan Subulus Salam Gg. Gunung Sari 2 RT.35 No.27','Jalan Subulus Salam Gg. Gunung Sari 2 RT